var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"통신기는 아직 고장인가?","JPN":"通信機はまだ故障しているのか？","ENG":"Are the comms still not working?","TWN":"通訊器還是壞的嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하바키…… 어디로 숨은 거냐?","JPN":"覇吐……どこに隠れたのだ。","ENG":"Habaki... Where are you?","TWN":"幅木……到底躲在哪裡？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"큭…… 팔의 통증이……","JPN":"くっ……腕の痛みが……","ENG":"Kgh...! My arm...","TWN":"唔……我的手臂……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"회복은커녕 오히려 악화되고 있군.","JPN":"回復はおろか、むしろ悪化している。","ENG":"It seems that my condition is worsening.","TWN":"怎麼沒有好轉，反而還更嚴重。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"안돼…… 난…… 이런 곳에서 끝날 순 없어.","JPN":"嫌だ……わしは…… こんなところで終われぬ。","ENG":"No... This... This cannot be the end for me.","TWN":"不可以……我……我不會就此罷休的！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_20"},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……이 목소린?","JPN":"……この声は？","ENG":"...This voice?","TWN":"……這個聲音是？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하바키!","JPN":"覇吐！","ENG":"Habaki!","TWN":"幅木！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"너…… 네 녀석이 어떻게 날 찾아낸 거냐?","JPN":"お前……どうしてわしの居場所がわかった？","ENG":"You... How did you find me?","TWN":"你……你是怎麼找到我的？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"질문을 하는 건 이쪽이다. 네놈의 동료는 어디에 있지?","JPN":"質問はこちらからだ。お前の仲間はどこにいる？","ENG":"We will be the ones asking questions. Where are your colleagues?","TWN":"你先回答我，你的同夥呢？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"흐흐…… 동료라.","JPN":"ふふ……仲間か。","ENG":"Keke... \\"Colleagues\\", eh?","TWN":"呵呵……什麼同夥。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그런 건 애초에 없었다. 나도, 녀석도…… 다른 목적을 가지고 서로를 이용했을 뿐이지.","JPN":"そんなものは最初からいなかった。わしも、やつも……違う目的でお互いを利用しただけだ。","ENG":"I never had any. He, as well as I... We both used each other for our own good.","TWN":"才沒有什麼同夥，我們只是因為要達成各自的目的……彼此利用而已。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"녀석이 먼저 내 뒤통수를 치는 건…… 예상 밖이었지만 말이야.","JPN":"やつが先にわしを裏切ったのは……予想外だったがな。","ENG":"But I could not expect... that he would betray me first.","TWN":"只是我沒想到……我竟然先被他擺一道。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그들이 널 배신했다고?","JPN":"彼らがお前を裏切っただと？","ENG":"They betrayed you?","TWN":"他們背叛你嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그래…… 놈들이…… 역신을 깨우려 하고 있다.","JPN":"そうだ……やつらは……疫病神を目覚めさせようとしている。","ENG":"Yes... They are... trying to awaken the Plague God.","TWN":"沒錯……他們……打算喚醒瘟神。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"역신 오로치는 이미 봉인됐다. 힘을 잃은 지금 오로치가 현실로 올라오는 건 불가능해.","JPN":"疫病神オロチはすでに封印された。力を失っている今、オロチが現実に上がってくることは不可能だ。","ENG":"Orochi has already been sealed. Without her powers, it is impossible for her to come up here.","TWN":"瘟神大蛇已經被封印起來，失去力量的大蛇現在是不可能來到現世的。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"오로치가 아니다……","JPN":"オロチではない……","ENG":"I am not talking about Orochi...","TWN":"不是大蛇……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"놈들은 결계옥…… 잠든 명부신의 영혼을 깨우려는 게야……","JPN":"やつらは結界玉……眠っている冥府の神の魂を起こすつもりだ……","ENG":"Akaitama... They are trying to awaken the soul of the Nether God...","TWN":"他們是想用結界玉石……喚醒沉睡的冥府神……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"何だと？","ENG":"What?","TWN":"你說什麼？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그렇다면 놈들이 결계를 노린 것도……?","JPN":"だとすると、やつらが結界を狙ったのも……？","ENG":"Then the reason for targeting the barrier is also...?","TWN":"那他們覬覦結界也是因為……？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"크흐흐…… 그래…… 명부신의 영혼을 강제로 깨우기 위해…… 저승을 현실로 불러들인 게다.","JPN":"クフフ……そうだ……冥府の神の魂を強制的に目覚めさせるため……冥府を現実に呼び入れる気だ。","ENG":"Kekeke... Yes... In order to forcibly awaken the Nether God... they needed to bring the Afterlife to reality.","TWN":"呵呵呵……沒錯……他們要強行喚醒冥府神的靈魂……於是將地獄召喚到現世來。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"하지만 걱정 마라…… 명부신의 부활은…… 내가 막을 테니까……","JPN":"だが心配するな……冥府の神の復活は……わしが止める……","ENG":"But do not worry... I will stop... his resurrection...","TWN":"不過別擔心……我會阻止……冥府神復活的……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하바키! 그 검은 상처는 설마……?","JPN":"覇吐！　その黒い傷はもしかして……？","ENG":"Habaki! That blackened wound...","TWN":"幅木！你的傷口難道是……？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"신의 그릇을…… <color=#ff3636>없애주겠어……</color>","JPN":"神の器を……<color=#ff3636>消してやる……</color>","ENG":"I will... <color=#ff3636>eliminate...</color> the god's vessel...","TWN":"神的器皿……<color=#ff3636>不該存在……</color>"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_08"},{"id":"L40_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"<color=#ff3636>이 하바키가- 역신이 될 존재를 뿌리뽑을 것이다아아아아……!</color>","JPN":"<color=#ff3636>この覇吐が……疫病神となる存在を取り除くのだああああ……！</color>","ENG":"<color=#ff3636>I, Habaki! Will rip the root of all who would become a Plague God...!</color>","TWN":"<color=#ff3636>我幅木- 會將成為瘟神的存在斬草除根……！</color>"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};